import scala.util.{Try, Success, Failure}
import scala.xml.{Elem, Node, XML}

final case class Settings(values: Map[String, String])

final case class ParseResult(settings: Settings, rootLabel: String)

object XmlConfigService {
  def parseSettingsFromApiRequest(xmlInput: String): Either[String, ParseResult] = {
    parseXml(xmlInput).flatMap(extractSettings)
  }

  private def parseXml(xmlInput: String): Either[String, Elem] = {
    if (xmlInput == null || xmlInput.trim.isEmpty) {
      Left("XML input is empty")
    } else {
      Try(XML.loadString(xmlInput)) match {
        case Success(xml) => Right(xml)
        case Failure(ex)  => Left(s"Invalid XML: ${ex.getMessage}")
      }
    }
  }

  private def extractSettings(root: Elem): Either[String, ParseResult] = {
    val directSettings = (root \ "setting").flatMap(parseSettingNode).toMap
    val nestedSettings = (root \\ "settings" \\ "setting").flatMap(parseSettingNode).toMap
    val merged = directSettings ++ nestedSettings

    Right(
      ParseResult(
        settings = Settings(merged),
        rootLabel = root.label
      )
    )
  }

  private def parseSettingNode(node: Node): Option[(String, String)] = {
    val key = (node \ "@key").text.trim
    val valueAttr = (node \ "@value").text.trim
    val valueText = node.text.trim
    val value = if (valueAttr.nonEmpty) valueAttr else valueText

    if (key.nonEmpty) Some(key -> value) else None
  }
}

